import React, { useEffect, useState } from 'react';
import './Internship.css';

const API_BASE = 'http://localhost:5000'; // Change if backend is hosted elsewhere

export default function Internship() {
  const user = JSON.parse(localStorage.getItem('currentUser'));
  const [internships, setInternships] = useState([]);
  const [filteredInternships, setFilteredInternships] = useState([]);
  const [search, setSearch] = useState('');
  const [modalOpen, setModalOpen] = useState(false);
  const [editingInternship, setEditingInternship] = useState(null);
  const [form, setForm] = useState({
    title: '',
    company: '',
    location: '',
    stipend: '',
    duration: '',
    description: '',
    requirements: '',
    applyBy: '',
  });

  // Fetch internships
  const fetchInternships = async () => {
    const res = await fetch(`${API_BASE}/api/internships`);
    const data = await res.json();
    setInternships(data);
    setFilteredInternships(data);
  };

  useEffect(() => {
    fetchInternships();
  }, []);

  // Filter logic
  useEffect(() => {
    const searchLower = search.toLowerCase();
    setFilteredInternships(
      internships.filter(i =>
        i.title.toLowerCase().includes(searchLower) ||
        i.company.toLowerCase().includes(searchLower)
      )
    );
  }, [search, internships]);

  const handleOpenModal = () => {
    setEditingInternship(null);
    setForm({
      title: '',
      company: '',
      location: '',
      stipend: '',
      duration: '',
      description: '',
      requirements: '',
      applyBy: '',
    });
    setModalOpen(true);
  };

  const handleEdit = internship => {
    setEditingInternship(internship);
    setForm(internship);
    setModalOpen(true);
  };

  const handleDelete = async id => {
    if (window.confirm('Delete this internship?')) {
      await fetch(`${API_BASE}/api/internships/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${user.token}` },
      });
      fetchInternships();
    }
  };

  const handleApply = async id => {
    const res = await fetch(`${API_BASE}/api/applications`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${user.token}`,
      },
      body: JSON.stringify({ internshipId: id }),
    });
    if (res.ok) alert('Applied successfully!');
    else alert('Already applied or error!');
  };

  const handleSave = async () => {
    const method = editingInternship ? 'PUT' : 'POST';
    const url = editingInternship
      ? `${API_BASE}/api/internships/${editingInternship._id}`
      : `${API_BASE}/api/internships`;

    const res = await fetch(url, {
      method,
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${user.token}`,
      },
      body: JSON.stringify(form),
    });

    if (res.ok) {
      setModalOpen(false);
      fetchInternships();
    } else {
      alert('Error saving internship');
    }
  };

  return (
    <div className="internship-page">
      <h2>Internship Opportunities</h2>

      <input
        type="text"
        placeholder="Search by title or company"
        value={search}
        onChange={e => setSearch(e.target.value)}
        className="search-input"
      />

      {(user?.role === 'admin' || user?.role === 'hr') && (
        <button onClick={handleOpenModal} className="add-internship-btn">
          + Add Internship
        </button>
      )}

      <div className="internship-list">
        {filteredInternships.map(i => (
          <div key={i._id} className="internship-card">
            <h3>{i.title}</h3>
            <p><strong>Company:</strong> {i.company}</p>
            <p><strong>Location:</strong> {i.location}</p>
            <p><strong>Stipend:</strong> {i.stipend}</p>
            <p><strong>Duration:</strong> {i.duration}</p>
            <p><strong>Description:</strong> {i.description}</p>
            <p><strong>Requirements:</strong> {i.requirements}</p>
            <p><strong>Apply By:</strong> {i.applyBy}</p>

            {user?.role === 'student' && (
              <button onClick={() => handleApply(i._id)} className="apply-btn">
                Apply
              </button>
            )}

            {(user?.role === 'admin' || user?.role === 'hr') && (
              <div className="admin-actions">
                <button onClick={() => handleEdit(i)} className="edit-btn">
                  Edit
                </button>
                <button onClick={() => handleDelete(i._id)} className="delete-btn">
                  Delete
                </button>
              </div>
            )}
          </div>
        ))}
      </div>

      {modalOpen && (
        <div className="modal">
          <div className="modal-content">
            <h3>{editingInternship ? 'Edit Internship' : 'Add Internship'}</h3>
            {Object.keys(form).map(field => (
              <input
                key={field}
                type={field === 'applyBy' ? 'date' : 'text'}
                placeholder={field.charAt(0).toUpperCase() + field.slice(1)}
                value={form[field]}
                onChange={e => setForm({ ...form, [field]: e.target.value })}
              />
            ))}
            <button onClick={handleSave} className="save-btn">Save</button>
            <button onClick={() => setModalOpen(false)} className="cancel-btn">Cancel</button>
          </div>
        </div>
      )}
    </div>
  );
}
